// Encode SKILLAI receiver payload
const message = encodeAbiParameters(
  [{ type:'address'},{type:'uint256'},{type:'uint256'},{type:'bool'}],
  [agent, skillId, amount, true]
);

// Pad receiver to bytes32 for LayerZero
const receiver = ('0x' + SKILLAI_RECEIVER.slice(2).padStart(64, '0')) as Hex;

await wallet.writeContract({
  address: LZ_ENDPOINT, abi: LZ_ABI, functionName: 'send',
  args: [{
    dstEid: 30101, // Ethereum mainnet endpoint id
    receiver, message,
    options: '0x00030100210100000000000000000000000000030d40',
    payInLzToken: false
  }, refundAddress],
  value: layerZeroFee
});
